class SecureSearchQueryBuilder:
    """
    Builds parameterized SQL queries safely using psycopg2.sql module.
    All identifiers are escaped, all values are parameterized.
    No string interpolation of user input into SQL.
    """

    def __init__(self, table_name: str):
        if table_name not in SEARCHABLE_SCHEMA:
            raise ValueError(f"Table '{table_name}' is not searchable")
        self.table_name = table_name
        self.schema = SEARCHABLE_SCHEMA[table_name]
        self.conditions = []
        self.params = []
        self.param_counter = 0

    def _all_fields(self):
        return (
            self.schema["text_fields"]
            + self.schema["numeric_fields"]
            + self.schema["boolean_fields"]
            + self.schema["date_fields"]
        )

    def _validate_field(self, field_name: str, allowed_types: list = None):
        """Validate field exists in whitelist."""
        all_fields = self._all_fields()
        if field_name not in all_fields:
            raise ValueError(
                f"Field '{field_name}' is not searchable on table '{self.table_name}'. "
                f"Allowed fields: {all_fields}"
            )
        if allowed_types:
            valid = False
            for field_type in allowed_types:
                if field_name in self.schema.get(field_type, []):
                    valid = True
                    break
            if not valid:
                raise ValueError(
                    f"Field '{field_name}' does not support the requested operation type"
                )

    def _next_param(self):
        self.param_counter += 1
        return f"p{self.param_counter}"

    def add_text_search(self, field: str, value: str, operator: str = "ilike"):
        """Add a text search condition."""
        self._validate_field(field, ["text_fields"])
        if operator not in ("like", "ilike", "eq"):
            raise ValueError(f"Invalid text operator: {operator}")

        col = sql.Identifier(field)

        if operator == "eq":
            self.conditions.append(sql.SQL("{} = %s").format(col))
            self.params.append(value)
        elif operator == "ilike":
            self.conditions.append(sql.SQL("{} ILIKE %s").format(col))
            self.params.append(f"%{value}%")
        elif operator == "like":
            self.conditions.append(sql.SQL("{} LIKE %s").format(col))
            self.params.append(f"%{value}%")

    def add_full_text_search(self, field: str, query: str, language: str = "english"):
        """Add PostgreSQL full-text search condition."""
        self._validate_field(field, ["text_fields"])
        allowed_languages = {"english", "simple", "spanish", "french", "german"}
        if language not in allowed_languages:
            raise ValueError(f"Unsupported FTS language: {language}")

        col = sql.Identifier(field)
        self.conditions.append(
            sql.SQL("to_tsvector({}, coalesce({}, '')) @@ plainto_tsquery({}, %s)").format(
                sql.Literal(language), col, sql.Literal(language)
            )
        )
        self.params.append(query)

    def add_multi_field_text_search(self, fields: list, value: str):
        """Search across multiple text fields with OR logic."""
        sub_conditions = []
        for field in fields:
            self._validate_field(field, ["text_fields"])
            col = sql.Identifier(field)
            sub_conditions.append(sql.SQL("{} ILIKE %s").format(col))
            self.params.append(f"%{value}%")

        if sub_conditions:
            combined = sql.SQL(" OR ").join(sub_conditions)
            self.conditions.append(sql.SQL("({})").format(combined))

    def add_numeric_filter(self, field: str, operator: str, value):
        """Add numeric comparison condition."""
        self._validate_field(field, ["numeric_fields"])
        col = sql.Identifier(field)

        op_map = {
            "eq": "=",
            "neq": "!=",
            "gt": ">",
            "gte": ">=",
            "lt": "<",
            "lte": "<=",
        }

        if operator == "between":
            if not isinstance(value, (list, tuple)) or len(value) != 2:
                raise ValueError("BETWEEN requires a list of exactly 2 values")
            self.conditions.append(
                sql.SQL("{} BETWEEN %s AND %s").format(col)
            )
            self.params.extend([float(value[0]), float(value[1])])
        elif operator in op_map:
            self.conditions.append(
                sql.SQL("{} {} %s").format(col, sql.SQL(op_map[operator]))
            )
            self.params.append(float(value))
        else:
            raise ValueError(f"Invalid numeric operator: {operator}")

    def add_boolean_filter(self, field: str, value: bool):
        """Add boolean filter."""
        self._validate_field(field, ["boolean_fields"])
        col = sql.Identifier(field)
        self.conditions.append(sql.SQL("{} = %s").format(col))
        self.params.append(bool(value))

    def add_date_filter(self, field: str, operator: str, value):
        """Add date comparison filter."""
        self._validate_field(field, ["date_fields"])
        col = sql.Identifier(field)

        op_map = {
            "eq": "=",
            "gt": ">",
            "gte": ">=",
            "lt": "<",
            "lte": "<=",
        }

        if operator == "between":
            if not isinstance(value, (list, tuple)) or len(value) != 2:
                raise ValueError("BETWEEN requires exactly 2 date values")
            self.conditions.append(
                sql.SQL("{} BETWEEN %s AND %s").format(col)
            )
            self.params.extend([value[0], value[1]])
        elif operator in op_map:
            self.conditions.append(
                sql.SQL("{} {} %s").format(col, sql.SQL(op_map[operator]))
            )
            self.params.append(value)
        else:
            raise ValueError(f"Invalid date operator: {operator}")

    def add_in_filter(self, field: str, values: list):
        """Add IN clause filter."""
        self._validate_field(field)
        col = sql.Identifier(field)
        if not values:
            raise ValueError("IN filter requires at least one value")
        placeholders = sql.SQL(", ").join([sql.Placeholder()] * len(values))
        self.conditions.append(
            sql.SQL("{} IN ({})").format(col, placeholders)
        )
        self.params.extend(values)

    def add_null_check(self, field: str, is_null: bool = True):
        """Check if a field is NULL or NOT NULL."""
        self._validate_field(field)
        col = sql.Identifier(field)
        if is_null:
            self.conditions.append(sql.SQL("{} IS NULL").format(col))
        else:
            self.conditions.append(sql.SQL("{} IS NOT NULL").format(col))

    def build(self, sort_field: str = None, sort_direction: str = "asc",
              limit: int = DEFAULT_LIMIT, offset: int = 0,
              count_only: bool = False):
        """Build the final parameterized query."""
        table = sql.Identifier(self.table_name)

        if count_only:
            query = sql.SQL("SELECT COUNT(*) as total FROM {}").format(table)
        else:
            query = sql.SQL("SELECT * FROM {}").format(table)

        if self.conditions:
            where_clause = sql.SQL(" AND ").join(self.conditions)
            query = sql.SQL("{} WHERE {}").format(query, where_clause)

        if not count_only:
            # Sort
            if sort_field:
                if sort_field not in self.schema["sortable_fields"]:
                    raise ValueError(
                        f"Cannot sort by '{sort_field}'. "
                        f"Allowed: {self.schema['sortable_fields']}"
                    )
                if sort_direction.lower() not in ALLOWED_SORT_DIRECTIONS:
                    raise ValueError(f"Invalid sort direction: {sort_direction}")

                sort_col = sql.Identifier(sort_field)
                direction = sql.SQL("ASC" if sort_direction.lower() == "asc" else "DESC")
                query = sql.SQL("{} ORDER BY {} {}").format(query, sort_col, direction)

            # Pagination
            limit = min(int(limit), MAX_LIMIT)
            offset = max(int(offset), 0)
            query = sql.SQL("{} LIMIT %s OFFSET %s").format(query)
            self.params.extend([limit, offset])

        return query, self.params


