# --- Search Resolver Logic ---

def execute_search(table_name, text_filters=None, numeric_filters=None,
                   date_filters=None, boolean_filters=None, in_filters=None,
                   full_text_search=None, keyword=None, sort=None,
                   limit=DEFAULT_LIMIT, offset=0):
    """Execute a secure parameterized search query."""

    builder = SecureSearchQueryBuilder(table_name)

    # Apply keyword search (searches across all text fields)
    if keyword:
        text_fields = SEARCHABLE_SCHEMA[table_name]["text_fields"]
        builder.add_multi_field_text_search(text_fields, keyword)

    # Apply text filters
    if text_filters:
        for tf in text_filters:
            builder.add_text_search(tf.field, tf.value, tf.get("operator", "ilike"))

    # Apply full-text search
    if full_text_search:
        for fts in full_text_search:
            builder.add_full_text_search(
                fts.field, fts.query, fts.get("language", "english")
            )

    # Apply numeric filters
    if numeric_filters:
        for nf in numeric_filters:
            if nf.operator == "between":
                builder.add_numeric_filter(
                    nf.field, "between", [nf.value_min, nf.value_max]
                )
            else:
                builder.add_numeric_filter(nf.field, nf.operator, nf.value)

    # Apply date filters
    if date_filters:
        for df in date_filters:
            if df.operator == "between":
                builder.add_date_filter(
                    df.field, "between", [df.value_min, df.value_max]
                )
            else:
                builder.add_date_filter(df.field, df.operator, df.value)

    # Apply boolean filters
    if boolean_filters:
        for bf in boolean_filters:
            builder.add_boolean_filter(bf.field, bf.value)

    # Apply IN filters
    if in_filters:
        for inf in in_filters:
            builder.add_in_filter(inf.field, list(inf.values))

    # Get sort params
    sort_field = sort.field if sort else None
    sort_direction = sort.direction if sort else "asc"

    # Build count query (need separate builder for count)
    count_builder = SecureSearchQueryBuilder(table_name)

    # Re-apply all filters to count builder
    if keyword:
        text_fields = SEARCHABLE_SCHEMA[table_name]["text_fields"]
        count_builder.add_multi_field_text_search(text_fields, keyword)
    if text_filters:
        for tf in text_filters:
            count_builder.add_text_search(tf.field, tf.value, tf.get("operator", "ilike"))
    if full_text_search:
        for fts in full_text_search:
            count_builder.add_full_text_search(fts.field, fts.query, fts.get("language", "english"))
    if numeric_filters:
        for nf in numeric_filters:
            if nf.operator == "between":
                count_builder.add_numeric_filter(nf.field, "between", [nf.value_min, nf.value_max])
            else:
                count_builder.add_numeric_filter(nf.field, nf.operator, nf.value)
    if date_filters:
        for df in date_filters:
            if df.operator == "between":
                count_builder.add_date_filter(df.field, "between", [df.value_min, df.value_max])
            else:
                count_builder.add_date_filter(df.field, df.operator, df.value)
    if boolean_filters:
        for bf in boolean_filters:
            count_builder.add_boolean_filter(bf.field, bf.value)
    if in_filters:
        for inf in in_filters:
            count_builder.add_in_filter(inf.field, list(inf.values))

    count_query, count_params = count_builder.build(count_only=True)
    data_query, data_params = builder.build(
        sort_field=sort_field,
        sort_direction=sort_direction,
        limit=limit,
        offset=offset
    )

    with get_db_cursor() as cursor:
        # Execute count query
        cursor.execute(count_query, count_params)
        total = cursor.fetchone()["total"]

        # Execute data query
        cursor.execute(data_query, data_params)
        rows = cursor.fetchall()

    actual_limit = min(int(limit), MAX_LIMIT)
    actual_offset = max(int(offset), 0)

    pagination = PaginationInfo(
        total=total,
        limit=actual_limit,
        offset=actual_offset,
        has_next=(actual_offset + actual_limit) < total,
        has_previous=actual_offset > 0,
    )

    # Convert datetime objects to strings
    items = []
    for row in rows:
        item = dict(row)
        for key, val in item.items():
            if isinstance(val, datetime):
                item[key] = val.isoformat()
        items.append(item)

    return items, pagination


