class Query(ObjectType):
    search_products = Field(
        ProductSearchResult,
        keyword=String(description="Search across all text fields"),
        text_filters=List(TextFilterInput),
        numeric_filters=List(NumericFilterInput),
        date_filters=List(DateFilterInput),
        boolean_filters=List(BooleanFilterInput),
        in_filters=List(InFilterInput),
        full_text_search=List(FullTextSearchInput),
        sort=Argument(SortInput),
        limit=Int(default_value=DEFAULT_LIMIT),
        offset=Int(default_value=0),
    )

    search_users = Field(
        UserSearchResult,
        keyword=String(),
        text_filters=List(TextFilterInput),
        boolean_filters=List(BooleanFilterInput),
        date_filters=List(DateFilterInput),
        in_filters=List(InFilterInput),
        sort=Argument(SortInput),
        limit=Int(default_value=DEFAULT_LIMIT),
        offset=Int(default_value=0),
    )

    search_orders = Field(
        OrderSearchResult,
        keyword=String(),
        text_filters=List(TextFilterInput),
        numeric_filters=List(NumericFilterInput),
        date_filters=List(DateFilterInput),
        in_filters=List(InFilterInput),
        sort=Argument(SortInput),
        limit=Int(default_value=DEFAULT_LIMIT),
        offset=Int(default_value=0),
    )

    product_by_id = Field(ProductType, id=Int(required=True))
    user_by_id = Field(UserType, id=Int(required=True))

    def resolve_search_products(self, info, **kwargs):
        try:
            items, pagination = execute_search("products", **kwargs)
            product_items = [ProductType(**item) for item in items]
            return ProductSearchResult(items=product_items, pagination=pagination)
        except ValueError as e:
            raise Exception(str(e))

    def resolve_search_users(self, info, **kwargs):
        try:
            items, pagination = execute_search("users", **kwargs)
            user_items = [UserType(**item) for item in items]
            return UserSearchResult(items=user_items, pagination=pagination)
        except ValueError as e:
            raise Exception(str(e))

    def resolve_search_orders(self, info, **kwargs):
        try:
            items, pagination = execute_search("orders", **kwargs)
            order_items = [OrderType(**item) for item in items]
            return OrderSearchResult(items=order_items, pagination=pagination)
        except ValueError as e:
            raise Exception(str(e))

    def resolve_product_by_id(self, info, id):
        with get_db_cursor() as cursor:
            cursor.execute(
                sql.SQL("SELECT * FROM {} WHERE id = %s").format(
                    sql.Identifier("products")
                ),
                [id]
            )
            row = cursor.fetchone()
            if row:
                item = dict(row)
                for key, val in item.items():
                    if isinstance(val, datetime):
                        item[key] = val.isoformat()
                return ProductType(**item)
            return None

    def resolve_user_by_id(self, info, id):
        with get_db_cursor() as cursor:
            cursor.execute(
                sql.SQL("SELECT * FROM {} WHERE id = %s").format(
                    sql.Identifier("users")
                ),
                [id]
            )
            row = cursor.fetchone()
            if row:
                item = dict(row)
                for key, val in item.items():
                    if isinstance(val, datetime):
                        item[key] = val.isoformat()
                return UserType(**item)
            return None


# --- Flask App Setup ---

schema = Schema(query=Query)

app = Flask(__name__)

app.add_url_rule(
    "/graphql",
    view_func=GraphQLView.as_view("graphql", schema=schema, graphiql=True),
)


@app.teardown_appcontext
def close_pool(exception):
    pass


@app.route("/health")
def health():
    try:
        with get_db_cursor() as cursor:
            cursor.execute("SELECT 1")
        return {"status": "healthy", "database": "connected"}, 200
    except Exception as e:
        return {"status": "unhealthy", "error": str(e)}, 500


